private struct WhatsAppChatsScreen: View {
    @State private var selected: WhatsAppChatThread? = nil
    private let threads = WhatsAppDemoData.threads

    var body: some View {
        NavigationStack {
            List(threads) { thread in
                Button { selected = thread } label: {
                    WhatsAppChatRow(thread: thread)
                }
                .buttonStyle(.plain)
                .listRowInsets(EdgeInsets(top: 8, leading: 16, bottom: 8, trailing: 16))
                .listRowSeparatorTint(WhatsAppTokens.waDividerLight.opacity(0.5))
            }
            .listStyle(.plain)
            .navigationTitle("Chats")
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button {} label: { Image(systemName: "square.and.pencil") }
                }
            }
            .navigationDestination(item: $selected) { thread in
                WhatsAppChatDetailScreen(thread: thread)
            }
        }
    }
}

private struct WhatsAppChatRow: View {
    let thread: WhatsAppChatThread
    var body: some View {
        HStack(spacing: 12) {
            Circle()
                .fill(thread.avatarColor.gradient)
                .frame(width: 48, height: 48)
                .overlay(Text(thread.initials).font(.system(size: 18, weight: .semibold)).foregroundStyle(.white))
                .overlay(Circle().strokeBorder(WhatsAppTokens.waGreen, lineWidth: thread.unread > 0 ? 2.5 : 0))
            VStack(alignment: .leading, spacing: 4) {
                HStack {
                    Text(thread.name).font(WhatsAppFonts.waContactName).foregroundStyle(WhatsAppTokens.waTextPrimary)
                    Spacer()
                    Text(thread.time).font(.system(size: 12)).foregroundStyle(WhatsAppTokens.waTextSecondary)
                }
                HStack {
                    Text(thread.preview).font(.system(size: 15)).foregroundStyle(WhatsAppTokens.waTextSecondary).lineLimit(1)
                    Spacer()
                    if thread.unread > 0 {
                        Text("\(thread.unread)").font(.system(size: 12, weight: .semibold)).foregroundStyle(.white)
                            .padding(.horizontal, 7).padding(.vertical, 3)
                            .background(Capsule().fill(WhatsAppTokens.waGreen))
                    }
                }
            }
        }
        .frame(height: 56)
    }
}

private struct WhatsAppChatDetailScreen: View {
    let thread: WhatsAppChatThread
    @State private var draft = ""
    var body: some View {
        VStack(spacing: 0) {
            ScrollView {
                VStack(spacing: 8) {
                    WhatsAppSystemBanner(text: "Messages are end-to-end encrypted.")
                    ForEach(thread.messages) { msg in
                        if msg.outgoing {
                            WhatsAppOutgoingBubble(text: msg.text, time: msg.time, accent: WhatsAppTokens.waOutgoingLight, textColor: WhatsAppTokens.waTextPrimary, readColor: WhatsAppTokens.waReadBlue)
                        } else {
                            WhatsAppIncomingBubble(text: msg.text, time: msg.time, fill: WhatsAppTokens.waIncomingLight, textColor: WhatsAppTokens.waTextPrimary)
                        }
                    }
                }
                .padding(.vertical, 12)
            }
            .background(WhatsAppTokens.waWallpaperLight)
            WhatsAppComposeBar(text: $draft, accent: WhatsAppTokens.waGreen)
        }
        .navigationTitle(thread.name)
        .navigationBarTitleDisplayMode(.inline)
    }
}

private struct WhatsAppOutgoingBubble: View {
    let text: String; let time: String; let accent: Color; let textColor: Color; let readColor: Color
    var body: some View {
        HStack {
            Spacer(minLength: 60)
            VStack(alignment: .trailing, spacing: 4) {
                Text(text).font(.system(size: 17)).foregroundStyle(textColor)
                HStack(spacing: 3) {
                    Text(time).font(.system(size: 11)).foregroundStyle(textColor.opacity(0.6))
                    Image(systemName: "checkmark").font(.system(size: 11, weight: .bold)).foregroundStyle(readColor)
                    Image(systemName: "checkmark").font(.system(size: 11, weight: .bold)).foregroundStyle(readColor).offset(x: -6)
                }
            }
            .padding(.vertical, 8).padding(.horizontal, 12)
            .background(UnevenRoundedRectangle(topLeadingRadius: 12, bottomLeadingRadius: 12, bottomTrailingRadius: 0, topTrailingRadius: 12).fill(accent))
        }
        .padding(.horizontal, 8)
    }
}

private struct WhatsAppIncomingBubble: View {
    let text: String; let time: String; let fill: Color; let textColor: Color
    var body: some View {
        HStack {
            VStack(alignment: .leading, spacing: 4) {
                Text(text).font(.system(size: 17)).foregroundStyle(textColor)
                Text(time).font(.system(size: 11)).foregroundStyle(textColor.opacity(0.6))
            }
            .padding(.vertical, 8).padding(.horizontal, 12)
            .background(UnevenRoundedRectangle(topLeadingRadius: 12, bottomLeadingRadius: 0, bottomTrailingRadius: 12, topTrailingRadius: 12).fill(fill))
            Spacer(minLength: 60)
        }
        .padding(.horizontal, 8)
    }
}

private struct WhatsAppComposeBar: View {
    @Binding var text: String
    let accent: Color
    var body: some View {
        HStack(spacing: 12) {
            Image(systemName: "face.smiling").font(.system(size: 22)).foregroundStyle(.secondary)
            TextField("Message", text: $text, axis: .vertical)
                .padding(.horizontal, 14).padding(.vertical, 8)
                .background(RoundedRectangle(cornerRadius: 20).fill(Color(.systemBackground)))
            Button {} label: {
                Image(systemName: text.isEmpty ? "mic.fill" : "paperplane.fill")
                    .font(.system(size: 18, weight: .semibold)).foregroundStyle(.white)
                    .frame(width: 36, height: 36).background(Circle().fill(accent))
            }
        }
        .padding(.horizontal, 12).padding(.vertical, 8)
        .background(.bar)
    }
}

